import secureStorage from '../utils/secureStorage';
import encryptionService from '../utils/encryptionService';

const PAYMENT_METHODS_KEY = 'payment_methods';
const BILLING_ADDRESS_KEY = 'billing_address';
const TRANSACTION_HISTORY_KEY = 'transaction_history';

class PaymentInfoManager {
  static maskCardNumber(cardNumber) {
    const cleaned = cardNumber.replace(/\s/g, '');
    if (cleaned.length < 4) return '****';
    return `****-****-****-${cleaned.slice(-4)}`;
  }

  static validateCardNumber(cardNumber) {
    const cleaned = cardNumber.replace(/\s|-/g, '');
    if (!/^\d{13,19}$/.test(cleaned)) return false;

    // Luhn algorithm
    let sum = 0;
    let isEven = false;

    for (let i = cleaned.length - 1; i >= 0; i--) {
      let digit = parseInt(cleaned[i], 10);

      if (isEven) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }

      sum += digit;
      isEven = !isEven;
    }

    return sum % 10 === 0;
  }

  static sanitizePaymentMethod(method) {
    return {
      id: method.id || encryptionService.generateToken(16),
      cardholderName: method.cardholderName,
      cardNumberHash: encryptionService.hashData(method.cardNumber || ''),
      cardNumberMasked: this.maskCardNumber(method.cardNumber || ''),
      encryptedCardNumber: method.cardNumber
        ? encryptionService.encrypt(method.cardNumber)
        : undefined,
      expiryMonth: method.expiryMonth,
      expiryYear: method.expiryYear,
      cardType: method.cardType || this.detectCardType(method.cardNumber || ''),
      encryptedCvv: method.cvv ? encryptionService.encrypt(method.cvv) : undefined,
      isDefault: method.isDefault || false,
      billingAddressId: method.billingAddressId,
      createdAt: method.createdAt || Date.now(),
      updatedAt: Date.now(),
    };
  }

  static detectCardType(cardNumber) {
    const cleaned = cardNumber.replace(/\s|-/g, '');

    if (/^4/.test(cleaned)) return 'visa';
    if (/^5[1-5]/.test(cleaned) || /^2[2-7]/.test(cleaned)) return 'mastercard';
    if (/^3[47]/.test(cleaned)) return 'amex';
    if (/^6(?:011|5)/.test(cleaned)) return 'discover';
    if (/^35(?:2[89]|[3-8])/.test(cleaned)) return 'jcb';
    if (/^3(?:0[0-5]|[68])/.test(cleaned)) return 'diners';

    return 'unknown';
  }

  static async savePaymentMethod(paymentMethod) {
    try {
      if (paymentMethod.cardNumber && !this.validateCardNumber(paymentMethod.cardNumber)) {
        throw new Error('Invalid card number');
      }

      const existingMethods = (await secureStorage.getItem(PAYMENT_METHODS_KEY)) || [];
      const sanitized = this.sanitizePaymentMethod(paymentMethod);

      if (sanitized.isDefault) {
        existingMethods.forEach((m) => {
          m.isDefault = false;
        });
      }

      const existingIndex = existingMethods.findIndex((m) => m.id === sanitized.id);
      if (existingIndex >= 0) {
        existingMethods[existingIndex] = sanitized;
      } else {
        existingMethods.push(sanitized);
      }

      await secureStorage.setItem(PAYMENT_METHODS_KEY, existingMethods);
      return sanitized;
    } catch (error) {
      console.error('Failed to save payment method:', error.message);
      throw error;
    }
  }

  static async getPaymentMethods() {
    try {
      const methods = (await secureStorage.getItem(PAYMENT_METHODS_KEY)) || [];

      return methods.map((method) => ({
        id: method.id,
        cardholderName: method.cardholderName,
        cardNumberMasked: method.cardNumberMasked,
        expiryMonth: method.expiryMonth,
        expiryYear: method.expiryYear,
        cardType: method.cardType,
        isDefault: method.isDefault,
        createdAt: method.createdAt,
        updatedAt: method.updatedAt,
      }));
    } catch (error) {
      console.error('Failed to get payment methods:', error.message);
      throw error;
    }
  }

  static async getFullPaymentMethod(id) {
    try {
      const methods = (await secureStorage.getItem(PAYMENT_METHODS_KEY)) || [];
      const method = methods.find((m) => m.id === id);

      if (!method) return null;

      return {
        ...method,
        cardNumber: method.encryptedCardNumber
          ? encryptionService.decrypt(method.encryptedCardNumber)
          : null,
        cvv: method.encryptedCvv ? encryptionService.decrypt(method.encryptedCvv) : null,
      };
    } catch (error) {
      console.error('Failed to get full payment method:', error.message);
      throw error;
    }
  }

  static async removePaymentMethod(id) {
    try {
      const methods = (await secureStorage.getItem(PAYMENT_METHODS_KEY)) || [];
      const filtered = methods.filter((m) => m.id !== id);
      await secureStorage.setItem(PAYMENT_METHODS_KEY, filtered);
      return true;
    } catch (error) {
      console.error('Failed to remove payment method:', error.message);
      throw error;
    }
  }

  static async saveBillingAddress(address) {
    try {
      const sanitized = {
        id: address.id || encryptionService.generateToken(16),
        fullName: address.fullName,
        addressLine1: address.addressLine1,
        addressLine2: address.addressLine2 || '',
        city: address.city,
        state: address.state,
        postalCode: address.postalCode,
        country: address.country,
        phone: address.phone,
        updatedAt: Date.now(),
      };

      const existing = (await secureStorage.getItem(BILLING_ADDRESS_KEY)) || [];
      const index = existing.findIndex((a) => a.id === sanitized.id);

      if (index >= 0) {
        existing[index] = sanitized;
      } else {
        existing.push(sanitized);
      }

      await secureStorage.setItem(BILLING_ADDRESS_KEY, existing);
      return sanitized;
    } catch (error) {
      console.error('Failed to save billing address:', error.message);
      throw error;
    }
  }

  static async getBillingAddresses() {
    try {
      return (await secureStorage.getItem(BILLING_ADDRESS_KEY)) || [];
    } catch (error) {
      console.error('Failed to get billing addresses:', error.message);
      throw error;
    }
  }

  static async saveTransaction(transaction) {
    try {
      const record = {
        id: transaction.id || encryptionService.generateToken(16),
        paymentMethodId: transaction.paymentMethodId,
        amount: transaction.amount,
        currency: transaction.currency || 'USD',
        status: transaction.status,
        description: transaction.description,
        merchantName: transaction.merchantName,
        timestamp: Date.now(),
      };

      const history = (await secureStorage.getItem(TRANSACTION_HISTORY_KEY)) || [];
      history.unshift(record);

      // Keep only last 100 transactions
      if (history.length > 100) {
        history.length = 100;
      }

      await secureStorage.setItem(TRANSACTION_HISTORY_KEY, history);
      return record;
    } catch (error) {
      console.error('Failed to save transaction:', error.message);
      throw error;
    }
  }

  static async getTransactionHistory(limit = 50) {
    try {
      const history = (await secureStorage.getItem(TRANSACTION_HISTORY_KEY)) || [];
      return history.slice(0, limit);
    } catch (error) {
      console.error('Failed to get transaction history:', error.message);
      throw error;
    }
  }

  static async clearAllPaymentData() {
    try {
      await secureStorage.multiRemove([
        PAYMENT_METHODS_KEY,
        BILLING_ADDRESS_KEY,
        TRANSACTION_HISTORY_KEY,
      ]);
      return true;
    } catch (error) {
      console.error('Failed to clear payment data:', error.message);
      throw error;
    }
  }
}

export default PaymentInfoManager;

