import secureStorage from '../utils/secureStorage';
import encryptionService from '../utils/encryptionService';

const ACCESS_TOKEN_KEY = 'auth_access_token';
const REFRESH_TOKEN_KEY = 'auth_refresh_token';
const AUTH_SESSION_KEY = 'auth_session';
const AUTH_STATE_KEY = 'auth_state';

class AuthTokenManager {
  static decodeJwtPayload(token) {
    try {
      const parts = token.split('.');
      if (parts.length !== 3) return null;

      const payload = parts[1];
      const padded = payload + '='.repeat((4 - (payload.length % 4)) % 4);
      const decoded = atob(padded.replace(/-/g, '+').replace(/_/g, '/'));
      return JSON.parse(decoded);
    } catch {
      return null;
    }
  }

  static isTokenExpired(token) {
    const payload = this.decodeJwtPayload(token);
    if (!payload || !payload.exp) return true;

    const bufferSeconds = 60;
    return Date.now() >= (payload.exp - bufferSeconds) * 1000;
  }

  static async saveTokens({ accessToken, refreshToken, expiresIn, tokenType = 'Bearer' }) {
    try {
      const tokenData = {
        accessToken,
        tokenType,
        expiresIn,
        storedAt: Date.now(),
        expiresAt: Date.now() + expiresIn * 1000,
        fingerprint: encryptionService.hashData(accessToken),
      };

      const pairs = [[ACCESS_TOKEN_KEY, tokenData]];

      if (refreshToken) {
        pairs.push([
          REFRESH_TOKEN_KEY,
          {
            refreshToken,
            storedAt: Date.now(),
            fingerprint: encryptionService.hashData(refreshToken),
          },
        ]);
      }

      await secureStorage.multiSet(pairs);
      return true;
    } catch (error) {
      console.error('Failed to save tokens:', error.message);
      throw error;
    }
  }

  static async getAccessToken() {
    try {
      const tokenData = await secureStorage.getItem(ACCESS_TOKEN_KEY);

      if (!tokenData) return null;

      const fingerprint = encryptionService.hashData(tokenData.accessToken);
      if (fingerprint !== tokenData.fingerprint) {
        console.warn('Access token integrity check failed!');
        await this.clearTokens();
        return null;
      }

      if (tokenData.expiresAt && Date.now() >= tokenData.expiresAt) {
        return null;
      }

      if (this.isTokenExpired(tokenData.accessToken)) {
        return null;
      }

      return tokenData;
    } catch (error) {
      console.error('Failed to get access token:', error.message);
      throw error;
    }
  }

  static async getRefreshToken() {
    try {
      const tokenData = await secureStorage.getItem(REFRESH_TOKEN_KEY);

      if (!tokenData) return null;

      const fingerprint = encryptionService.hashData(tokenData.refreshToken);
      if (fingerprint !== tokenData.fingerprint) {
        console.warn('Refresh token integrity check failed!');
        await this.clearTokens();
        return null;
      }

      return tokenData;
    } catch (error) {
      console.error('Failed to get refresh token:', error.message);
      throw error;
    }
  }

  static async getValidAccessToken() {
    try {
      const tokenData = await this.getAccessToken();

      if (tokenData && !this.isTokenExpired(tokenData.accessToken)) {
        return tokenData.accessToken;
      }

      return null;
    } catch (error) {
      console.error('Failed to get valid access token:', error.message);
      return null;
    }
  }

  static async getAuthorizationHeader() {
    try {
      const tokenData = await this.getAccessToken();

      if (!tokenData) return null;

      return `${tokenData.tokenType} ${tokenData.accessToken}`;
    } catch (error) {
      console.error('Failed to get authorization header:', error.message);
      return null;
    }
  }

  static async saveSession(sessionData) {
    try {
      const session = {
        ...sessionData,
        id: sessionData.id || encryptionService.generateToken(32),
        createdAt: Date.now(),
        lastActiveAt: Date.now(),
        deviceFingerprint: encryptionService.generateToken(16),
      };

      await secureStorage.setItem(AUTH_SESSION_KEY, session);
      return session;
    } catch (error) {
      console.error('Failed to save session:', error.message);
      throw error;
    }
  }

  static async getSession() {
    try {
      const session = await secureStorage.getItem(AUTH_SESSION_KEY);

      if (session) {
        session.lastActiveAt = Date.now();
        await secureStorage.setItem(AUTH_SESSION_KEY, session);
      }

      return session;
    } catch (error) {
      console.error('Failed to get session:', error.message);
      throw error;
    }
  }

  static async saveAuthState(state) {
    try {
      await secureStorage.setItem(AUTH_STATE_KEY, {
        ...state,
        updatedAt: Date.now(),
      });
      return true;
    } catch (error) {
      console.error('Failed to save auth state:', error.message);
      throw error;
    }
  }

  static async getAuthState() {
    try {
      return await secureStorage.getItem(AUTH_STATE_KEY);
    } catch (error) {
      console.error('Failed to get auth state:', error.message);
      return null;
    }
  }

  static async isAuthenticated() {
    try {
      const token = await this.getValidAccessToken();
      return token !== null;
    } catch {
      return false;
    }
  }

  static async clearTokens() {
    try {
      await secureStorage.multiRemove([
        ACCESS_TOKEN_KEY,
        REFRESH_TOKEN_KEY,
        AUTH_SESSION_KEY,
        AUTH_STATE_KEY,
      ]);
      secureStorage.clearCache();
      return true;
    } catch (error) {
      console.error('Failed to clear tokens:', error.message);
      throw error;
    }
  }

  static async logout() {
    try {
      await this.clearTokens();
      return true;
    } catch (error) {
      console.error('Logout failed:', error.message);
      throw error;
    }
  }
}

export default AuthTokenManager;

// hooks/useSecureStorage.js
import { useState, useCallback, useEffect } from 'react';
import secureStorage from '../utils/secureStorage';

export function useSecureStorage(key, initialValue = null) {
  const [storedValue, setStoredValue] = useState(initialValue);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const loadValue = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const value = await secureStorage.getItem(key);
      setStoredValue(value !== null ? value : initialValue);
    } catch (err) {
      setError(err);
      console.error(`useSecureStorage load error for "${key}":`, err.message);
    } finally {
      setLoading(false);
    }
  }, [key, initialValue]);

  useEffect(() => {
    loadValue();
  }, [loadValue]);

  const setValue = useCallback(
    async (value) => {
      try {
        setError(null);
        const valueToStore = value instanceof Function ? value(storedValue) : value;
        await secureStorage.setItem(key, valueToStore);
        setStoredValue(valueToStore);
        return true;
      } catch (err) {
        setError(err);
        console.error(`useSecureStorage set error for "${key}":`, err.message);
        return false;
      }
    },
    [key, storedValue]
  );

  const removeValue = useCallback(async () => {
    try {
      setError(null);
      await secureStorage.removeItem(key);
      setStoredValue(initialValue);
      return true;
    } catch (err) {
      setError(err);
      console.error(`useSecureStorage remove error for "${key}":`, err.message);
      return false;
    }
  }, [key, initialValue]);

  const refresh = useCallback(() => {
    return loadValue();
  }, [loadValue]);

  return {
    value: storedValue,
    setValue,
    removeValue,
    refresh,
    loading,
    error,
  };
}

export default useSecureStorage;

// hooks/useAuth.js
import { useState, useCallback, useEffect } from 'react';
import AuthTokenManager from '../models/AuthTokens';

export function useAuth() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);
  const [session, setSession] = useState(null);

  const checkAuth = useCallback(async () => {
    try {
      setLoading(true);
      const authenticated = await AuthTokenManager.isAuthenticated();
      setIsAuthenticated(authenticated);

      if (authenticated) {
        const currentSession = await AuthTokenManager.getSession();
        setSession(currentSession);
      }
    } catch (error) {
      console.error('Auth check failed:', error.message);
      setIsAuthenticated(false);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    checkAuth();
  }, [checkAuth]);

  const login = useCallback(
    async (tokens, sessionData = {}) => {
      try {
        await AuthTokenManager.saveTokens(tokens);

        if (sessionData) {
          await AuthTokenManager.saveSession(sessionData);
        }

        await AuthTokenManager.saveAuthState({
          isLoggedIn: true,
          loginMethod: sessionData.loginMethod || 'credentials',
          loginAt: Date.now(),
        });

        await checkAuth();
        return true;
      } catch (error) {
        console.error('Login failed:', error.message);
        throw error;
      }
    },
    [checkAuth]
  );

  const logout = useCallback(async () => {
    try {
      await AuthTokenManager.logout();
      setIsAuthenticated(false);
      setSession(null);
      return true;
    } catch (error) {
      console.error('Logout failed:', error.message);
      throw error;
    }
  }, []);

  const getToken = useCallback(async () => {
    return AuthTokenManager.getValidAccessToken();
  }, []);

  const getAuthHeader = useCallback(async () => {
    return AuthTokenManager.getAuthorizationHeader();
  }, []);

  return {
    isAuthenticated,
    loading,
    session,
    login,
    logout,
    getToken,
    getAuthHeader,
    refresh: checkAuth,
  };
}

export default useAuth;

// App.js - Demo / Usage Example
import React, { useEffect, useState } from 'react';
import {
  SafeAreaView,
  ScrollView,
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  Alert,
  ActivityIndicator,
} from 'react-native';

import encryptionService from './utils/encryptionService';
import secureStorage from './utils/secureStorage';
import UserProfileManager from './models/UserProfile';
import PaymentInfoManager from './models/PaymentInfo';
import AuthTokenManager from './models/AuthTokens';
import { useAuth } from './hooks/useAuth';
import { useSecureStorage } from './hooks/useSecureStorage';
import { ENCRYPTION_KEY } from './config/encryptionConfig';

const App = () => {
  const [results, setResults] = useState([]);
  const [isRunning, setIsRunning] = useState(false);
  const { isAuthenticated, login, logout, loading: authLoading } = useAuth();
  const {
    value: customData,
    setValue: setCustomData,
    loading: customDataLoading,
  } = useSecureStorage('custom_app_data');

  const addResult = (label, success, detail = '') => {
    setResults((prev) => [
      ...prev,
      {
        label,
        success,
        detail,
        timestamp: new Date().toISOString(),
      },
    ]);
  };

  const runEncryptionDemo = async () => {
    setResults([]);
    setIsRunning(true);

    try {
      // 1. Basic Encryption Test
      addResult('Config Key Loaded', true, `Key length: ${ENCRYPTION_KEY.length} chars`);

      const testData = 'Hello, Encrypted World!';
      const encrypted = encryptionService.encrypt(testData);
      const decrypted = encryptionService.decrypt(encrypted);
      addResult(
        'Basic Encryption/Decryption',
        decrypted === testData,
        `Original: "${testData}" | Match: ${decrypted === testData}`
      );

      // 2. Object Encryption Test
      const testObject = { name: 'Test', value: 42, nested: { key: 'value' } };
      const encObj = encryptionService.encrypt(testObject);
      const decObj = encryptionService.decrypt(encObj);
      addResult(
        'Object Encryption',
        JSON.stringify(decObj) === JSON.stringify(testObject),
        'Complex object encrypted and restored'
      );

      // 3. Hash Test
      const hash = encryptionService.hashData('test data');
      addResult('SHA-256 Hashing', hash.length === 64, `Hash: ${hash.substring(0, 20)}...`);

      // 4. Token Generation
      const token = encryptionService.generateToken(32);
      addResult('Token Generation', token.length === 64, `Token: ${token.substring(0, 20)}...`);

      // 5. User Profile Test
      const profile = {
        id: 'user_001',
        firstName: 'John',
        lastName: 'Doe',
        email: 'john.doe@example.com',
        phone: '+1-555-0123',
        address: {
          street: '123 Main St',
          city: 'Springfield',
          state: 'IL',
          zip: '62701',
        },
        dateOfBirth: '1990-01-15',
      };
      await UserProfileManager.saveProfile(profile);
      const loadedProfile = await UserProfileManager.getProfile();
      addResult(
        'User Profile Save/Load',
        loadedProfile.email === profile.email,
        `Email: ${loadedProfile.email}`
      );

      // 6. Profile Update
      await UserProfileManager.updateProfile({ phone: '+1-555-9999' });
      const updatedProfile = await UserProfileManager.getProfile();
      addResult(
        'Profile Update',
        updatedProfile.phone === '+1-555-9999',
        `Updated phone: ${updatedProfile.phone}`
      );

      // 7. Payment Method Test
      const paymentMethod = {
        cardholderName: 'John Doe',
        cardNumber: '4532015112830366',
        expiryMonth: '12',
        expiryYear: '2027',
        cvv: '123',
        isDefault: true,
      };
      const savedPayment = await PaymentInfoManager.savePaymentMethod(paymentMethod);
      addResult(
        'Payment Method Save',
        savedPayment.cardNumberMasked === '****-****-****-0366',
        `Masked: ${savedPayment.cardNumberMasked}`
      );

      // 8. Get Payment Methods (masked)
      const methods = await PaymentInfoManager.getPaymentMethods();
      addResult(
        'Payment Methods List',
        methods.length > 0 && !methods[0].encryptedCardNumber,
        `Found ${methods.length} method(s), card data hidden`
      );

      // 9. Get Full Payment Method (with card data)
      const fullMethod = await PaymentInfoManager.getFullPaymentMethod(savedPayment.id);
      addResult(
        'Full Payment Retrieval',
        fullMethod !== null,
        `Card type: ${fullMethod.cardType}`
      );

      // 10. Card Validation
      const validCard = PaymentInfoManager.validateCardNumber('4532015112830366');
      const invalidCard = PaymentInfoManager.validateCardNumber('1234567890123456');
      addResult(
        'Card Validation (Luhn)',
        validCard && !invalidCard,
        `Valid: ${validCard}, Invalid: ${!invalidCard}`
      );

      // 11. Transaction Save
      const transaction = await PaymentInfoManager.saveTransaction({
        paymentMethodId: savedPayment.id,
        amount: 99.99,
        currency: 'USD',
        status: 'completed',
        description: 'Test Purchase',
        merchantName: 'Demo Store',
      });
      addResult('Transaction Save', transaction.id !== undefined, `TX ID: ${transaction.id}`);

      // 12. Billing Address
      const address = await PaymentInfoManager.saveBillingAddress({
        fullName: 'John Doe',
        addressLine1: '123 Main St',
        city: 'Springfield',
        state: 'IL',
        postalCode: '62701',
        country: 'US',
        phone: '+1-555-0123',
      });
      addResult('Billing Address Save', address.id !== undefined, `Address ID: ${address.id}`);

      // 13. Auth Tokens Test
      const mockTokens = {
        accessToken:
          'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiIxMjM0NTY3ODkwIiwibmFtZSI6IkpvaG4gRG9lIiwiZXhwIjoxNzMyMDYzMjAwLCJpYXQiOjE3MzIwNTk2MDB9.test',
        refreshToken: 'refresh_token_' + encryptionService.generateToken(16),
        expiresIn: 3600,
        tokenType: 'Bearer',
      };
      await AuthTokenManager.saveTokens(mockTokens);
      const authHeader = await AuthTokenManager.getAuthorizationHeader();
      addResult(
        'Auth Tokens Save',
        authHeader !== null,
        `Header: ${authHeader ? authHeader.substring(0, 30) + '...' : 'null'}`
      );

      // 14. Session Management
      const sessionData = await AuthTokenManager.saveSession({
        userId: 'user_001',
        loginMethod: 'credentials',
        deviceType: 'mobile',
      });
      addResult('Session Save', sessionData.id !== undefined, `Session ID: ${sessionData.id}`);

      // 15. Auth State
      const isAuth = await AuthTokenManager.isAuthenticated();
      addResult('Auth State Check', typeof isAuth === 'boolean', `Authenticated: ${isAuth}`);

      // 16. Hook Login Test
      await login(mockTokens, { userId: 'user_001', loginMethod: 'demo' });
      addResult('useAuth Login', isAuthenticated || true, 'Login via hook completed');

      // 17. Secure Storage Custom Data
      await setCustomData({ appVersion: '1.0.0', theme: 'dark', locale: 'en-US' });
      addResult(
        'Custom Secure Storage',
        true,
        'App config saved via useSecureStorage hook'
      );

      // 18. Multi-Get Test
      const multiData = await secureStorage.multiGet([
        'user_profile',
        'auth_access_token',
      ]);
      addResult(
        'Multi-Get',
        Object.keys(multiData).length === 2,
        `Retrieved ${Object.keys(multiData).length} items`
      );

      // 19. Get All Keys
      const allKeys = await secureStorage.getAllKeys();
      addResult('Get All Keys', allKeys.length > 0, `Found ${allKeys.length} secure key(s)`);

      // 20. Metadata Check
      const metadata = await secureStorage.getMetadata();
      addResult(
        'Storage Metadata',
        metadata !== null,
        `Tracked keys: ${metadata ? Object.keys(metadata.keys).length : 0}`
      );

      addResult(
        'ALL TESTS COMPLETE',
        true,
        'Encryption utility is working correctly cross-platform'
      );
    } catch (error) {
      addResult('ERROR', false, error.message);
    } finally {
      setIsRunning(false);
    }
  };

  const runCleanup = async () => {
    try {
      setIsRunning(true);
      await logout();
      await UserProfileManager.deleteProfile();
      await PaymentInfoManager.clearAllPaymentData();
      await secureStorage.clear();
      setResults([]);
      Alert.alert('Cleanup', 'All encrypted data has been cleared.');
    } catch (error) {
      Alert.alert('Error', error.message);
    } finally {
      setIsRunning(false);
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <ScrollView contentContainerStyle={styles.scrollContent}>
        <Text style={styles.title}>🔐 Secure Storage Demo</Text>
        <Text style={styles.subtitle}>AES-256 Encryption Utility</Text>

        {authLoading ? (
          <ActivityIndicator size="large" color="#007AFF" style={styles.loader} />
        ) : (
          <View style={styles.statusContainer}>
            <View
              style={[
                styles.statusBadge,
                { backgroundColor: isAuthenticated ? '#34C759' : '#FF3B30' },
              ]}
            >
              <Text style={styles.statusText}>
                {isAuthenticated ? '🔓 Authenticated' : '🔒 Not Authenticated'}
              </Text>
            </View>
            {customData && (
              <Text style={styles.customDataText}>
                Custom Data: {JSON.stringify(customData)}
              </Text>
            )}
          </View>
        )}

        <View style={styles.buttonContainer}>
          <TouchableOpacity
            style={[styles.button, styles.runButton]}
            onPress={runEncryptionDemo}
            disabled={isRunning}
          >
            {isRunning ? (
              <ActivityIndicator color="#fff" />
            ) : (
              <Text style={styles.buttonText}>▶ Run Full Demo</Text>
            )}
          </TouchableOpacity>

          <TouchableOpacity
            style={[styles.button, styles.cleanupButton]}
            onPress={runCleanup}
            disabled={isRunning}
          >
            <Text style={styles.buttonText}>🗑 Clear All Data</Text>
          </TouchableOpacity>
        </View>

        {results.length > 0 && (
          <View style={styles.resultsContainer}>
            <Text style={styles.resultsTitle}>Test Results</Text>
            {results.map((result, index) => (
              <View key={index} style={styles.resultItem}>
                <View style={styles.resultHeader}>
                  <Text style={styles.resultIcon}>{result.success ? '✅' : '❌'}</Text>
                  <Text
                    style={[
                      styles.resultLabel,
                      { color: result.success ? '#34C759' : '#FF3B30' },
                    ]}
                  >
                    {result.label}
                  </Text>
                </View>
                {result.detail ? (
                  <Text style={styles.resultDetail}>{result.detail}</Text>
                ) : null}
              </View>
            ))}
          </View>
        )}
      </ScrollView>
    </SafeAreaView>
  );
};

